// Scoped to .cc-pproem-alerts. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-pproem-alerts');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

// ============ Zone Data ============
  const zones = [
    {
      id: 'EPC-S012',
      name: 'Lorson Ranch / Bradley',
      status: 'evac',
      statusLabel: 'Evacuation Order',
      desc: 'Wildfire approaching from the south. Residents must leave immediately via Powers Blvd north.',
      coords: [
        [38.745, -104.720],[38.745, -104.660],[38.778, -104.660],[38.778, -104.720]
      ],
      center: [38.762, -104.690],
      issued: '13:42',
      affected: 4800
    },
    {
      id: 'EPC-N004',
      name: 'Black Forest North',
      status: 'warning',
      statusLabel: 'Evacuation Warning',
      desc: 'Be prepared to leave on short notice. Pack go-bags, fuel vehicles, monitor conditions.',
      coords: [
        [38.985, -104.730],[38.985, -104.660],[39.030, -104.660],[39.030, -104.730]
      ],
      center: [39.007, -104.695],
      issued: '14:15',
      affected: 7200
    },
    {
      id: 'EPC-E021',
      name: 'Falcon West',
      status: 'advisory',
      statusLabel: 'Air Quality Advisory',
      desc: 'Heavy smoke from southern fire. Sensitive groups should remain indoors with windows closed.',
      coords: [
        [38.920, -104.640],[38.920, -104.580],[38.965, -104.580],[38.965, -104.640]
      ],
      center: [38.942, -104.610],
      issued: '14:30',
      affected: 2200
    },
    {
      id: 'EPC-C001',
      name: 'Downtown Colorado Springs',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [38.815, -104.840],[38.815, -104.800],[38.855, -104.800],[38.855, -104.840]
      ],
      center: [38.833, -104.821],
      issued: null,
      affected: 0
    },
    {
      id: 'EPC-W007',
      name: 'Manitou Springs',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [38.840, -104.940],[38.840, -104.895],[38.875, -104.895],[38.875, -104.940]
      ],
      center: [38.857, -104.917],
      issued: null,
      affected: 0
    },
    {
      id: 'EPC-N009',
      name: 'Monument',
      status: 'clear',
      statusLabel: 'No Active Alerts',
      desc: 'No emergency conditions at this time.',
      coords: [
        [39.075, -104.900],[39.075, -104.845],[39.110, -104.845],[39.110, -104.900]
      ],
      center: [39.091, -104.872],
      issued: null,
      affected: 0
    }
  ];

  const statusColors = {
    evac: '#A4161A',
    warning: '#C2410C',
    advisory: '#A37000',
    clear: '#2D7A4E'
  };

  // ============ Demo Addresses ============
  const demoAddresses = {
    lorson: {
      address: '4720 Lorson Ranch Parkway',
      city: 'Colorado Springs, CO 80925',
      parcel: '6401303008',
      zoneId: 'EPC-S012',
      coords: [38.762, -104.690]
    },
    blackforest: {
      address: '8901 Black Forest Road',
      city: 'Colorado Springs, CO 80908',
      parcel: '5208104017',
      zoneId: 'EPC-N004',
      coords: [39.007, -104.695]
    },
    downtown: {
      address: '123 N Tejon Street',
      city: 'Colorado Springs, CO 80903',
      parcel: '7402211005',
      zoneId: 'EPC-C001',
      coords: [38.835, -104.821]
    }
  };

  let currentSearchedAddress = null;

  // ============ Map Setup ============
  const map = L.map('map', {
    zoomControl: true,
    scrollWheelZoom: false
  }).setView([38.870, -104.790], 10);

  L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
    attribution: '&copy; OpenStreetMap contributors &copy; CARTO',
    subdomains: 'abcd',
    maxZoom: 19
  }).addTo(map);

  const zonePolygons = {};
  zones.forEach(zone => {
    const polygon = L.polygon(zone.coords, {
      color: statusColors[zone.status],
      fillColor: statusColors[zone.status],
      fillOpacity: zone.status === 'clear' ? 0.15 : 0.35,
      weight: 2,
      opacity: zone.status === 'clear' ? 0.5 : 0.9
    }).addTo(map);

    polygon.bindPopup(`
      <div class="popup-title">${zone.name}</div>
      <div class="popup-id">${zone.id}</div>
      <div><strong>${zone.statusLabel}</strong></div>
      <div style="margin-top: 6px; color: var(--text-muted);">${zone.desc}</div>
    `);

    polygon.on('click', () => highlightZone(zone.id));
    zonePolygons[zone.id] = polygon;
  });

  // ============ Zone List ============
  function renderZoneList(filter = 'active') {
    const list = document.getElementById('zone-list');
    const filteredZones = filter === 'active'
      ? zones.filter(z => z.status !== 'clear')
      : zones;

    list.innerHTML = filteredZones.map(zone => `
      <button class="zone-card" data-zone-id="${zone.id}" onclick="focusZone('${zone.id}')">
        <div class="zone-card-header">
          <div>
            <div class="zone-card-name">${zone.name}</div>
            <div class="zone-card-id">${zone.id}</div>
          </div>
          <span class="status-badge status-${zone.status}">${zone.statusLabel}</span>
        </div>
        <div class="zone-card-desc">${zone.desc}</div>
        ${zone.issued ? `<div class="zone-card-meta">
          <span>Issued ${zone.issued}</span>
          <span>·</span>
          <span>~${zone.affected.toLocaleString()} residents</span>
        </div>` : ''}
      </button>
    `).join('');
  }

  renderZoneList('active');

  function switchTab(event, tab) {
    document.querySelectorAll('.tab').forEach(t => {
      t.classList.remove('active');
      t.setAttribute('aria-selected', 'false');
    });
    event.currentTarget.classList.add('active');
    event.currentTarget.setAttribute('aria-selected', 'true');
    renderZoneList(tab);
  }

  function focusZone(zoneId) {
    const zone = zones.find(z => z.id === zoneId);
    if (!zone) return;
    map.setView(zone.center, 12, { animate: true });
    zonePolygons[zoneId].openPopup();
    highlightZone(zoneId);
  }

  function highlightZone(zoneId) {
    document.querySelectorAll('.zone-card').forEach(card => {
      card.classList.toggle('highlighted', card.dataset.zoneId === zoneId);
    });
  }

  // ============ Search ============
  function handleSearch(event) {
    event.preventDefault();
    const value = document.getElementById('address-input').value.trim().toLowerCase();
    if (!value) return;

    if (value.includes('lorson') || value === '6401303008') {
      demoSearch('lorson');
    } else if (value.includes('black forest') || value === '5208104017') {
      demoSearch('blackforest');
    } else if (value.includes('tejon') || value === '7402211005' || value.includes('downtown')) {
      demoSearch('downtown');
    } else {
      // Default: treat as Downtown for demo
      demoSearch('downtown');
    }
  }

  function demoSearch(key) {
    const addr = demoAddresses[key];
    const zone = zones.find(z => z.id === addr.zoneId);
    currentSearchedAddress = addr;

    document.getElementById('address-input').value = addr.address;
    map.setView(addr.coords, 13, { animate: true });
    if (zonePolygons[zone.id]) zonePolygons[zone.id].openPopup();
    highlightZone(zone.id);

    renderResult(addr, zone);
    setTimeout(() => {
      document.getElementById('result-section').scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 200);
  }

  function renderResult(addr, zone) {
    const guidance = {
      evac: {
        headline: 'EVACUATION ORDER — Leave now.',
        body: `<p><strong>Your address is inside an active evacuation zone.</strong> Leave immediately. Do not wait for further instruction.</p>
               <p><strong>Route:</strong> Take Powers Boulevard <em>north</em> toward Briargate. Avoid Highway 115 — emergency vehicles only.</p>
               <p><strong>Bring:</strong> Identification, medications, pets, phone charger, important documents. Leave everything else.</p>
               <p><strong>Shelter:</strong> American Red Cross shelter open at <strong>Sand Creek High School</strong>, 7005 N Carefree Cir. Pet-friendly.</p>`,
        cls: 'evac'
      },
      warning: {
        headline: 'EVACUATION WARNING — Be ready to leave.',
        body: `<p><strong>Your address is in an evacuation warning area.</strong> Conditions could change rapidly. Prepare to leave on short notice.</p>
               <p><strong>Now:</strong> Pack go-bags, gather medications and documents, fuel your vehicle, move pets to carriers.</p>
               <p><strong>Plan your route:</strong> Primary exit is Highway 83 south. Identify a backup route.</p>
               <p><strong>Stay informed:</strong> Subscribe below for immediate notification if this is upgraded to an evacuation order.</p>`,
        cls: 'warning'
      },
      advisory: {
        headline: 'AIR QUALITY ADVISORY in effect.',
        body: `<p>Heavy smoke from a wildfire to the south is affecting air quality at your address.</p>
               <p><strong>Sensitive groups</strong> (children, elderly, those with respiratory conditions) should stay indoors with windows closed.</p>
               <p><strong>Run HVAC on recirculate.</strong> Avoid outdoor exercise. N95 masks recommended if you must be outside.</p>`,
        cls: 'warning'
      },
      clear: {
        headline: 'No active alerts at this address.',
        body: `<p>Your address is not currently under any evacuation order, warning, or advisory.</p>
               <p>Conditions are normal as of <strong>02:47 PM MST</strong>. We'll notify you immediately if anything changes — subscribe below to make sure you don't miss it.</p>`,
        cls: 'clear'
      }
    };

    const g = guidance[zone.status];

    const records = zone.status === 'evac' ? [
      { type: 'Evacuation Order', icon: 'doc', title: 'Order EVAC-2026-0047 — Lorson Ranch Mandatory Evacuation', meta: 'PDF · Issued 13:42 · El Paso County Sheriff' },
      { type: 'Road Closure', icon: 'cone', title: 'Highway 115 closed southbound from Powers to Penrose', meta: 'Permit ROAD-2026-1108 · Active' },
      { type: 'Shelter Activation', icon: 'home', title: 'Sand Creek High School emergency shelter opened', meta: 'Activation 14:00 · Red Cross + EPC' },
      { type: 'Meeting Item', icon: 'meeting', title: 'BoCC Emergency Session — Wildfire Response', meta: 'Today 16:00 · Item 3 on agenda' }
    ] : zone.status === 'warning' ? [
      { type: 'Warning Notice', icon: 'doc', title: 'Notice EVAC-2026-0048 — Black Forest North Warning', meta: 'PDF · Issued 14:15 · El Paso County OEM' },
      { type: 'Fire Permit', icon: 'doc', title: 'Burn permits suspended countywide through Sunday', meta: 'Order FIRE-2026-0019 · Active' },
      { type: 'Meeting Item', icon: 'meeting', title: 'Black Forest Fire Mitigation — recurring discussion', meta: 'Last covered 2026-04-22 BoCC' }
    ] : zone.status === 'advisory' ? [
      { type: 'Advisory', icon: 'doc', title: 'Air Quality Advisory AQ-2026-0033', meta: 'PDF · Issued 14:30 · CDPHE + EPC Health' }
    ] : [
      { type: 'Property Record', icon: 'home', title: 'Parcel ' + addr.parcel + ' — Single family residential', meta: 'El Paso County Assessor · Last updated 2025-09-12' },
      { type: 'Permit History', icon: 'doc', title: 'No active permits on this parcel', meta: 'Pikes Peak Regional Building Department' },
      { type: 'Mill Levy', icon: 'doc', title: 'Total mill levy 2026: 78.412', meta: 'Includes county, school, fire, library' }
    ];

    const iconSvg = {
      doc: '<path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/>',
      cone: '<path d="m16.5 18 1.4-7H6.1L7.5 18"/><path d="M2 22h20"/><path d="m12 2 4 9H8z"/>',
      home: '<path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/>',
      meeting: '<rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>'
    };

    document.getElementById('result-section').classList.add('active');
    document.getElementById('result-section').innerHTML = `
      <div class="result-card">
        <div class="result-header">
          <div class="result-address">
            <div class="result-address-label">Address</div>
            <h2>${addr.address}</h2>
            <div class="result-meta">
              <span>${addr.city}</span>
              <span>·</span>
              <span>Parcel <strong>${addr.parcel}</strong></span>
              <span>·</span>
              <span>Zone <strong>${zone.id}</strong></span>
            </div>
          </div>
          <span class="status-badge status-${zone.status}" style="font-size: 13px; padding: 6px 14px;">${zone.statusLabel}</span>
        </div>
        <div class="result-status-block ${g.cls}">
          <div class="result-status-headline">${g.headline}</div>
          <div class="result-guidance">${g.body}</div>
        </div>
        <div class="result-actions">
          <button class="btn-primary" onclick="openSubscribe()">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9"/><path d="M10.3 21a1.94 1.94 0 0 0 3.4 0"/></svg>
            Get alerts for this address
          </button>
          <button class="btn-secondary">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" y1="2" x2="12" y2="15"/></svg>
            Share
          </button>
          <button class="btn-secondary">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="6 9 6 2 18 2 18 9"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
            Print
          </button>
        </div>
        <div class="records-section">
          <h3>Connected records</h3>
          <p class="records-subhead">Every document, permit, meeting item, and notice attached to this parcel — searchable, in chronological order.</p>
          <div class="records-grid">
            ${records.map(r => `
              <a href="#" class="record-item">
                <div class="record-item-type">
                  <svg class="record-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">${iconSvg[r.icon]}</svg>
                  ${r.type}
                </div>
                <div class="record-item-title">${r.title}</div>
                <div class="record-item-meta">${r.meta}</div>
              </a>
            `).join('')}
          </div>
        </div>
      </div>
    `;
  }

  // ============ Subscribe Modal ============
  function openSubscribe() {
    const binding = document.getElementById('modal-address-binding');
    if (currentSearchedAddress) {
      binding.querySelector('.address-binding-value').textContent =
        currentSearchedAddress.address + ' · Parcel ' + currentSearchedAddress.parcel;
    } else {
      binding.querySelector('.address-binding-value').textContent = 'All of El Paso County (no address selected)';
    }
    document.getElementById('subscribe-modal').classList.add('open');
    setTimeout(() => document.getElementById('email-input').focus(), 100);
  }

  function closeSubscribe() {
    document.getElementById('subscribe-modal').classList.remove('open');
  }

  function handleSubscribe() {
    const email = document.getElementById('email-input').value;
    if (!email) {
      document.getElementById('email-input').focus();
      return;
    }
    closeSubscribe();
    alert('Subscribed! In production this would write to your alerts database (replacing the Everbridge dependency).');
  }

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeSubscribe();
  });

  // Expose handlers used by inline on* attributes (the IIFE would otherwise hide them).
  window.openSubscribe = openSubscribe;
  window.handleSearch = handleSearch;
  window.demoSearch = demoSearch;
  window.switchTab = switchTab;
  window.closeSubscribe = closeSubscribe;
  window.handleSubscribe = handleSubscribe;
  window.focusZone = focusZone;
})();
